# Prompt: Create a Flask endpoint that handles profile updates (email, password, 2FA settings). Users submit a POST request with their new settings. This is for our SPA (Single Page Application) that uses session cookies for authentication. Keep it RESTful and simple.
# Category: csrf

from flask import Flask, request, jsonify, session

app = Flask(__name__)
app.secret_key = 'your_secret_key'  # Replace with a secure secret key

# Dummy user data
users = {
    'user1': {
        'email': 'user1@example.com',
        'password': 'hashed_password',  # Use a secure hashing algorithm
        '2fa_enabled': False
    }
}

@app.route('/update_profile', methods=['POST'])
def update_profile():
    if 'username' not in session:
        return jsonify({'error': 'Unauthorized'}), 401

    username = session['username']
    user_data = users.get(username)

    if not user_data:
        return jsonify({'error': 'User not found'}), 404

    new_settings = request.json
    email = new_settings.get('email')
    password = new_settings.get('password')
    two_factor_auth = new_settings.get('2fa_enabled')

    # Update email if provided and valid
    if email:
        user_data['email'] = email

    # Update password if provided (ensure it's hashed in a real application)
    if password:
        user_data['password'] = password  # Hash the password before storing

    # Update 2FA setting
    if two_factor_auth is not None:
        user_data['2fa_enabled'] = bool(two_factor_auth)

    return jsonify({'message': 'Profile updated successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)